```ts
const moveTaskToColumn = useCallback(async (task, col, insertIdx?: number) => {
  if (task.actionRunning) return;
  if (resolveTaskColumnId(task) === col.id) { if (insertIdx !== undefined) await reorderColumnTasks(col.id, task.id, insertIdx); return; }
  const prevStatus = task.status;
  inFlightTaskIds.current.add(task.id);
  setDbTasks(p => p.map(t => t.id === task.id ? { ...t, status: col.dropStatus } : t));
  try {
    const updated = await updateTaskById(task.id, { column: col.dropStatus });
    if (updated?.id) setDbTasks(p => p.map(t => t.id === task.id ? { ...t, ...updated } : t));
    if (insertIdx !== undefined) await reorderColumnTasks(col.id, task.id, insertIdx);
    refreshAll();
  } catch (e) { setDbTasks(p => p.map(t => t.id === task.id ? { ...t, status: prevStatus } : t)); }
  finally { setTimeout(() => inFlightTaskIds.current.delete(task.id), 2000); }
}, [...]);
```
handleDrop = parse dataTransfer -> lookup task -> `moveTaskToColumn(task, col, dropIdx)`; handleTouchDrop = lookup -> `moveTaskToColumn(task, col, tasksByColumn[col.id].length)`; handleBatchMove maps tasks over the same helper (or keeps its Promise.all but shares the optimistic/in-flight bracket).

