```ts
const ingestImageFiles = (files: File[]) => {
  for (const file of files) {
    if (!file.type.match(IMAGE_MIME_RE) || file.size > MAX_IMAGE_BYTES) continue;
    const reader = new FileReader();
    reader.onload = (ev) => { const m = String(ev.target?.result).match(DATA_URL_RE); if (m) onAddImages?.([{ mediaType: m[1], data: m[2], preview: ev.target.result }]); };
    reader.readAsDataURL(file);
  }
};
```
